  const extractNode = $('Extract from File2').first();
  readmeContent = extractNode.json?.data || extractNode.binary?.data || null;

  // Если данные в base64, декодируем
  if (readmeContent && typeof readmeContent !== 'string') {
    readmeContent = Buffer.from(readmeContent, 'base64').toString('utf-8');
  }
} catch (e) {
  console.log('Extract from File2 not found or empty');
}

// Шаг 2: Парсим Readme.md в словарь {id: название}
