if (readmeContent) {
  const lines = readmeContent.split('\n');
  for (const line of lines) {
    // Ищем строки вида: 67472790c37a3 - Skin Editor, Skin Maker
    const match = line.match(/^\s*`?([a-f0-9]{10,})`?\s*[-–—]\s*(.+)$/i);
    if (match) {
      const id = match[1].toLowerCase();
      const name = match[2].trim();
      contentNames[id] = name;
    }
  }
}

// Шаг 3: Получаем attachments из узла Get an issue7
const fileMap = {};
try {
  const issueItems = $('Get an issue7').all();

  for (const item of issueItems) {
    const attachments = item.json?.fields?.attachment || [];

    for (const att of attachments) {
      const content = att.content || '';
      if (typeof content !== 'string') continue;

      const lowerContent = content.toLowerCase();

      // Ищем только файлы с underscore (readme_ID или content_ID)
      if (!lowerContent.includes('readme_') && !lowerContent.includes('content_')) {
        continue;
      }

      let fileName = att.fileName || att.filename || att.name || '';
      if (!fileName) {
        const clean = content.split('?')[0].split('#')[0];
        fileName = clean.split('/').pop() || '';
      }

      if (!fileName) continue;

      // Извлекаем ID из имени файла
      const match = fileName.match(/[_/]([a-f0-9]{10,})/i);
      const fileId = match ? match[1].toLowerCase() : 'unknown';

      if (!fileMap[fileId]) {
        fileMap[fileId] = { 
          id: fileId, 
          readme: null, 
          content: null,
          contentName: contentNames[fileId] || 'Unknown'
        };
      }

      if (lowerContent.includes('readme_')) {
        fileMap[fileId].readme = fileName;
      } else if (lowerContent.includes('content_')) {
        fileMap[fileId].content = fileName;
      }
    }
  }
} catch (e) {
  console.log('Get an issue7 not found or empty');
}

return Object.values(fileMap).map(pair => ({
  json: pair
}));

// Берём текст из AI Agent
