const contentName = loopItem.contentName || 'Unknown';
const id = loopItem.id || 'unknown';
const itemIndex = loopItem.loopIndex || 1;  // <-- Берем готовый индекс

console.log('Item index:', itemIndex);

// Формируем имя файла
const safeFileName = `prompt_${contentName}_${id}_${itemIndex}.md`.replace(/[\/\\:*?"<>|,]/g, '_');

