    source: 'AI Agent',
    format: 'markdown',
    fileName: safeFileName,
    itemIndex: itemIndex,
  }
}];

const items = $input.all();
let foundReadme = null;
let fallbackReadme = null;

for (const item of items) {
  const attachments = item.json?.fields?.attachment || [];

  for (const att of attachments) {
    let fileName = att.fileName || att.filename || att.name || '';

    // Если имени нет, берем из URL
    if (!fileName && att.content) {
      const clean = att.content.split('?')[0].split('#')[0];
      fileName = clean.split('/').pop();
    }

    if (!fileName) continue;

    // Декодируем URL-encoded символы
    fileName = decodeURIComponent(fileName);

    // Извлекаем только имя файла (без пути)
    const baseName = fileName.split('/').pop().split('\\').pop();
    const lowerName = baseName.toLowerCase();

    // Извлекаем ID из URL
    const getAttachmentId = (attachment) => {
      let id = null;
      if (attachment.content) {
        const match = attachment.content.match(/\/attachment\/(\d+)\//);
        if (match) id = match[1];
      }
      if (!id && attachment.self) {
        const match = attachment.self.match(/\/attachment\/(\d+)$/);
        if (match) id = match[1];
      }
      if (!id && attachment.id) {
        id = attachment.id.toString();
      }
      return id;
    };

    // Приоритет 1: Чистый Readme.md (без underscore, без скобок)
    if (lowerName === 'readme.md' && 
        !baseName.includes('_') && 
        !baseName.match(/readme\s*\(\d+\)\.md/i)) {

      foundReadme = {
        attachmentId: getAttachmentId(att),
        fileName: baseName
      };
      break;
    }

    // Приоритет 2: Readme (1).md - сохраняем как fallback
    if (lowerName === 'readme (1).md' && !fallbackReadme) {
      fallbackReadme = {
        attachmentId: getAttachmentId(att),
        fileName: baseName
      };
    }
  }

  if (foundReadme) break;
}

// Возвращаем найденный или fallback
if (foundReadme) {
  return [{ json: foundReadme }];
} else if (fallbackReadme) {
  return [{ json: fallbackReadme }];
} else {
  return [
    {
      json: {
        attachmentId: null,
        error: 'Readme.md not found'
      }
    }
  ];
}

